"use client";
import { useState } from "react";
import Header from "@/components/Header";
import Sidebar from "@/components/Sidebar";
import LoanTable from "@/components/LoanTable";
import ReservationTable from "@/components/ReservationTable";
import FinesTable from "@/components/FinesTable";
import SettingsForm from "@/components/SettingsForm";
import AboutModal from "@/components/AboutModal";

export default function DashboardPage() {
    const [tab, setTab] = useState("loans");
    const [showModal, setShowModal] = useState(false);

    return (
        <>
            <Header onOpenAbout={() => setShowModal(true)} />
            <div className="container">
                <div className="dashboard-grid">
                    <Sidebar />
                    <main className="main-content">
                        <div className="tabs">
                            {["loans", "reservations", "fines", "settings"].map(id => (
                                <button key={id} className={`tab ${tab === id ? "active" : ""}`} onClick={() => setTab(id)}>
                                    {id === "loans" && "📋 История выдач"}
                                    {id === "reservations" && "📌 Активные бронирования"}
                                    {id === "fines" && "⚠️ Штрафы"}
                                    {id === "settings" && "⚙️ Настройки"}
                                </button>
                            ))}
                        </div>
                        {tab === "loans" && <LoanTable />}
                        {tab === "reservations" && <ReservationTable />}
                        {tab === "fines" && <FinesTable />}
                        {tab === "settings" && <SettingsForm />}
                    </main>
                </div>
            </div>
            {showModal && <AboutModal onClose={() => setShowModal(false)} />}
        </>
    );
}